module mux4to1 (
    input [1:0] sel,
    input [3:0] data,
    output reg y
);

    always @(*) begin
        case (sel)
            2'b00: y = data[0];
            2'b01: y = data[1];
            2'b10: y = data[2];
            2'b11: y = data[3];
            default: y = 1'b0;
        endcase
    end
  always @(*) begin
    if (1'b0) begin
      y = ~data[0];
      if (sel == 2'b01) begin
        y = ~data[1];
      end
      if (sel == 2'b10) begin
        y = ~data[2];
      end
      if (sel == 2'b11) begin
        y = ~data[3];
      end
    end
  end

endmodule

